glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float uTime;
uniform float uSeed;
uniform float uGrainScale;
uniform float uWashScale;
uniform float uVioletBias;
uniform float uCyanBias;
float hash(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7))+uSeed*17.13)*43758.5453);}
float noise(vec2 p){vec2 i=floor(p);vec2 f=fract(p);f=f*f*(3.0-2.0*f);float a=hash(i);float b=hash(i+vec2(1.0,0.0));float c=hash(i+vec2(0.0,1.0));float d=hash(i+vec2(1.0,1.0));return mix(mix(a,b,f.x),mix(c,d,f.x),f.y);} 
float fbm(vec2 p){float v=0.0;float a=0.5;for(int i=0;i<5;i++){v+=a*noise(p);p*=2.03;a*=0.52;}return v;}
void main(){vec2 p=vUv;float wash=fbm(p*uWashScale+vec2(0.0,uTime*0.006));float grain=hash(floor(p*uGrainScale))/255.0;float island=smoothstep(0.44,0.82,fbm(p*7.0+2.3));vec3 blue=vec3(0.14,0.24,0.46);vec3 cyan=vec3(0.17,0.55,0.66);vec3 violet=vec3(0.39,0.30,0.62);vec3 bruised=vec3(0.20,0.18,0.36);vec3 col=mix(blue,violet,uVioletBias*wash);col=mix(col,cyan,uCyanBias*smoothstep(0.35,0.78,fbm(p*4.5-1.7)));col=mix(col,bruised,0.22*(1.0-wash));col+=island*vec3(0.035,0.02,0.055);col+=grain*vec3(1.0);col*=0.92+0.08*fbm(p*28.0);gl_FragColor=vec4(col,1.0);}

