glsl.fragment:
precision mediump float;
varying vec2 vUv;
uniform float uTime;
uniform float uSeed;
uniform float uScale;
uniform float uEdgeFeather;
uniform float uCoolRedWeight;
float hash(vec2 p){return fract(sin(dot(p,vec2(41.7,289.3))+uSeed*9.1)*19341.7);} 
float noise(vec2 p){vec2 i=floor(p);vec2 f=fract(p);f=f*f*(3.0-2.0*f);return mix(mix(hash(i),hash(i+vec2(1,0)),f.x),mix(hash(i+vec2(0,1)),hash(i+vec2(1,1)),f.x),f.y);} 
float ellipse(vec2 p, vec2 c, vec2 r){vec2 q=(p-c)/r;return 1.0-dot(q,q);} 
void main(){vec2 p=(vUv-0.5)*2.0; p.y*=1.12;float drift=0.018*sin(uTime*0.18+p.y*2.0);p.x+=drift;float body=ellipse(p,vec2(-0.02,-0.02),vec2(0.48,0.30));float lobes=0.0;for(int i=0;i<7;i++){float fi=float(i);float x=-0.42+fi*0.14+0.018*sin(fi*4.7);float y=0.12+0.08*sin(fi*1.6);float rx=0.095+0.018*sin(fi*2.1);float ry=0.20+0.04*cos(fi*1.3);lobes=max(lobes,ellipse(p,vec2(x,y),vec2(rx,ry)));}float lower=max(ellipse(p,vec2(0.18,-0.18),vec2(0.28,0.13)),ellipse(p,vec2(-0.28,-0.16),vec2(0.20,0.10)));float shape=max(max(body,lobes),lower);float cut=ellipse(p,vec2(0.10,0.00),vec2(0.16,0.095));shape=min(shape,-cut+0.22);float edgeNoise=(noise(p*18.0+1.2)-0.5)*0.075;float alpha=smoothstep(-uEdgeFeather,uEdgeFeather,shape+edgeNoise);float stain=noise(p*22.0)+0.45*noise(p*52.0);vec3 coolRed=vec3(0.54,0.18,0.20);vec3 violetRed=vec3(0.42,0.20,0.34);vec3 ochre=vec3(0.66,0.47,0.20);vec3 muted=vec3(0.30,0.35,0.54);vec3 col=mix(violetRed,coolRed,uCoolRedWeight+0.15*stain);col=mix(col,ochre,0.16*smoothstep(0.45,0.85,stain));col=mix(col,muted,0.10*(1.0-stain));col*=0.82+0.18*stain;gl_FragColor=vec4(col,alpha*0.92);}

precision mediump float;
varying vec2 vUv;
uniform float uTime;
uniform float uStrokeDensity;
uniform float uWrapBias;
uniform float uRedAccent;
float curveLine(vec2 p,float y,float amp,float freq,float phase,float width){float cy=y+amp*sin((p.x+phase)*freq)+0.035*sin((p.x*2.7-phase)*freq*0.53);return 1.0-smoothstep(width,width+0.006,abs(p.y-cy));}
float loopLine(vec2 p,vec2 c,vec2 r,float width){vec2 q=(p-c)/r;float d=abs(length(q)-1.0);return 1.0-smoothstep(width,width+0.01,d);} 
void main(){vec2 p=(vUv-0.5)*2.0;p.y*=1.12;float t=uTime*0.02;float black=0.0;black=max(black,curveLine(p,-0.13,0.035,5.0,t,0.006));black=max(black,curveLine(p,0.18,0.030,4.2,-0.7+t,0.005));black=max(black,loopLine(p,vec2(-0.08,0.02),vec2(0.58,0.31),0.018));black=max(black,loopLine(p,vec2(0.13,0.00),vec2(0.22,0.13),0.014));float red=0.0;red=max(red,curveLine(p,0.02,0.020,6.1,1.8-t,0.004));red=max(red,loopLine(p,vec2(-0.31,0.08),vec2(0.18,0.24),0.012));float gate=smoothstep(-0.82,-0.15,p.x)*(1.0-smoothstep(0.78,0.95,p.x));float a=(black*0.78+red*uRedAccent)*gate*uStrokeDensity;vec3 col=mix(vec3(0.055,0.045,0.055),vec3(0.82,0.30,0.14),step(0.08,red)*0.58);gl_FragColor=vec4(col,a);}

precision mediump float;
varying vec2 vUv;
uniform float uTime;
uniform float uCenterX;
uniform float uCenterY;
uniform float uRadius;
uniform float uHandJitter;
float seg(vec2 p,vec2 a,vec2 b,float w){vec2 pa=p-a;vec2 ba=b-a;float h=clamp(dot(pa,ba)/dot(ba,ba),0.0,1.0);return 1.0-smoothstep(w,w+0.006,length(pa-ba*h));}
void main(){vec2 p=(vUv-0.5)*2.0;p.y*=1.12;vec2 c=vec2(uCenterX,uCenterY);float d=length(p-c);float dotFill=1.0-smoothstep(uRadius,uRadius+0.01,d);float ring=smoothstep(uRadius+0.012,uRadius+0.018,d)*(1.0-smoothstep(uRadius+0.04,uRadius+0.05,d));float j=uHandJitter*sin(uTime*0.12);float h1=seg(p,c,c+vec2(0.15+j,0.055),0.008);float h2=seg(p,c,c+vec2(-0.055,0.16-j),0.006);vec3 ochre=vec3(0.72,0.53,0.22);vec3 ink=vec3(0.06,0.045,0.04);vec3 col=mix(ochre,ink,clamp(h1+h2,0.0,1.0));float a=max(dotFill*0.95,ring*0.5);a=max(a,max(h1,h2)*0.88);gl_FragColor=vec4(col,a);}
